commits.content:
/* components/CustomDots.module.css */

.slickDots {
  position: absolute;
  bottom: 10px; /* Отступ снизу */
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  justify-content: center;
  align-items: center;
  list-style: none;
  padding: 0;
  margin: 0;
  z-index: 10;
}

.slickDot,
.slickDotActive {
  width: 12px; /* Размер точки */
  height: 12px; /* Размер точки */
  margin: 0 5px; /* Расстояние между точками */
  background-color: rgba(255, 255, 255, 0.5); /* Цвет неактивной точки */
  border-radius: 50%; /* Делаем точки круглыми */
  cursor: pointer;
  transition: background-color 0.3s ease; /* Плавный переход при наведении */
  border: none; /* Убираем рамку, если она есть по умолчанию */
}

.slickDotActive {
  background-color: #FF8C00; /* Цвет активной точки */
}

/* Стиль при наведении */
.slickDot:hover {
  background-color: rgba(255, 255, 255, 0.8); /* Более яркий белый при наведении */
}

.slickDotActive:hover {
  background-color: #FFA500; /* Цвет активной точки при наведении */
}
